from bisect import bisect_left, bisect_right
from collections import defaultdict

class SegmentTree:
    def __init__(self, start, end):
        self.start = start
        self.end = end
        self.left = None
        self.right = None
        self.max_sum = float('-inf')

    def update(self, index, value):
        if self.start == self.end:
            self.max_sum = max(self.max_sum, value)
            return
        mid = (self.start + self.end) // 2
        if index <= mid:
            if not self.left:
                self.left = SegmentTree(self.start, mid)
            self.left.update(index, value)
        else:
            if not self.right:
                self.right = SegmentTree(mid + 1, self.end)
            self.right.update(index, value)
        self.max_sum = max(self.left.max_sum if self.left else float('-inf'), self.right.max_sum if self.right else float('-inf'))

    def query(self, l, r):
        if r < self.start or l > self.end:
            return float('-inf')
        if l <= self.start and self.end <= r:
            return self.max_sum
        return max(self.left.query(l, r) if self.left else float('-inf'), self.right.query(l, r) if self.right else float('-inf'))

class Solution:
    def maxBalancedSubsequenceSum(self, nums: List[int]) -> int:
        n = len(nums)
        keys = [nums[i] - i for i in range(n)]
        min_key, max_key = min(keys), max(keys)

        # Coordinate compression
        sorted_keys = sorted(set(keys))
        key_to_index = {key: i for i, key in enumerate(sorted_keys)}

        # Initialize segment tree
        st = SegmentTree(0, len(sorted_keys) - 1)

        max_total = float('-inf')
        for i in range(n):
            key = keys[i]
            idx = key_to_index[key]
            current_val = nums[i]
            # Query max sum for keys <= current key
            max_prev = st.query(0, idx)
            current_sum = max(current_val, current_val + max_prev)
            max_total = max(max_total, current_sum)
            st.update(idx, current_sum)

        return max_total
